window.lazyTemplateMarkup=Object.freeze({roomModalTemplate:'\n        <div id="roomModal" class="modal">\n            <div class="modal-content">\n                <button class="close" id="closeModal" aria-label="Close modal">&times;</button>\n                <div class="modal-body">\n                    <div id="modalImage" class="modal-image">\n                        <div id="modalImagesWrapper" class="modal-images-wrapper"></div>\n                        <button class="modal-slider-btn modal-slider-prev" id="modalSliderPrev" aria-label="Previous image" style="display: none;">&#10094;</button>\n                        <button class="modal-slider-btn modal-slider-next" id="modalSliderNext" aria-label="Next image" style="display: none;">&#10095;</button>\n                        <div id="modalSliderDots" class="modal-slider-dots" style="display: none;"></div>\n                        <div id="modalImageCounter" class="modal-image-counter" style="display: none;"></div>\n                    </div>\n                    <div class="modal-info">\n                        <h2 id="modalTitle"></h2>\n                        <p id="modalDescription"></p>\n                        <div style="display: flex; gap: 10px; flex-wrap: wrap;">\n                            <button class="btn btn-primary btn-lg" id="modalBookBtn" data-i18n="modal-book-btn">Book This Room</button>\n                            <button class="btn btn-secondary btn-lg" onclick="return openInfoModal(\'houseRulesModal\');" data-i18n="house-rules">House Rules &amp; Policies</button>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    ',bookingConfirmationModalTemplate:'\n        <div id="bookingConfirmationModal" class="modal" style="display: none;">\n            <div class="modal-content" style="max-width: 600px; max-height: 90vh; overflow-y: auto;">\n                <button class="close" id="closeConfirmModal">&#215;</button>\n\n                <h2 style="margin-bottom: 20px; text-align: center; color: #2c3e50;">Booking Confirmation</h2>\n\n                <div style="background: #f8f9fa; padding: 15px; border-radius: 8px; margin-bottom: 20px;">\n                    <h3 style="margin-bottom: 10px; color: #34495e; font-size: 16px;">Booking Details</h3>\n                    <p style="margin: 8px 0;"><strong>Room:</strong> <span id="confirmRoomName"></span></p>\n                    <p style="margin: 8px 0;"><strong>Check-in:</strong> <span id="confirmCheckIn"></span></p>\n                    <p style="margin: 8px 0;"><strong>Check-out:</strong> <span id="confirmCheckOut"></span></p>\n                    <p style="margin: 8px 0;"><strong>Guests:</strong> <span id="confirmGuests"></span></p>\n                    <p style="margin: 8px 0;"><strong>Price per Night:</strong> <span id="confirmPricePerNight"></span></p>\n                    <p style="margin: 8px 0;"><strong>Number of Nights:</strong> <span id="confirmNights"></span></p>\n                    <p style="margin: 8px 0; font-size: 18px; color: #e74c3c;"><strong>Total Price: </strong><span id="confirmTotalPrice"></span></p>\n                </div>\n\n                <div style="margin-bottom: 20px;">\n                    <h3 style="margin-bottom: 10px; color: #34495e; font-size: 16px;">Guest Information</h3>\n                    <p style="margin: 8px 0;"><strong>Name:</strong> <span id="confirmGuestName"></span></p>\n                    <p style="margin: 8px 0;"><strong>Email:</strong> <span id="confirmGuestEmail"></span></p>\n                    <p style="margin: 8px 0;"><strong>Phone:</strong> <span id="confirmGuestPhone"></span></p>\n                </div>\n\n                <form id="bookingPaymentForm" style="background: #ecf0f1; padding: 15px; border-radius: 8px; margin-bottom: 20px;">\n                    <h3 style="margin-bottom: 15px; color: #34495e; font-size: 16px;">Payment Information</h3>\n\n                    <div style="margin-bottom: 15px;">\n                        <label for="paymentMethod" style="display: block; margin-bottom: 5px; font-weight: bold; color: #34495e;">Payment Method <span style="color: #e74c3c;">*</span></label>\n                        <select id="paymentMethod" name="paymentMethod" required style="width: 100%; padding: 8px; border: 1px solid #bdc3c7; border-radius: 4px; font-size: 14px;">\n                            <option value="">Select Payment Method</option>\n                            <option value="credit-card">Credit Card</option>\n                            <option value="debit-card">Debit Card</option>\n                            <option value="bank-transfer">Bank Transfer</option>\n                        </select>\n                    </div>\n\n                    <div id="cardDetails" style="display:none;"></div>\n\n                    <div style="margin-bottom: 15px;">\n                        <label style="display: flex; align-items: center; cursor: pointer;">\n                            <input type="checkbox" id="billingAddress" name="billingAddress" style="margin-right: 8px;">\n                            <span style="color: #34495e;">Add Billing Address</span>\n                        </label>\n                    </div>\n\n                    <div id="billingAddressForm" style="display: none; background: white; padding: 15px; border-radius: 4px; margin-bottom: 15px;">\n                        <div style="margin-bottom: 12px;">\n                            <input type="text" id="billingStreet" name="billingStreet" placeholder="Street Address" style="width: 100%; padding: 8px; border: 1px solid #bdc3c7; border-radius: 4px; box-sizing: border-box;">\n                        </div>\n                        <div style="display: grid; grid-template-columns: 2fr 1fr; gap: 10px; margin-bottom: 12px;">\n                            <input type="text" id="billingCity" name="billingCity" placeholder="City" style="padding: 8px; border: 1px solid #bdc3c7; border-radius: 4px; box-sizing: border-box;">\n                            <input type="text" id="billingPostal" name="billingPostal" placeholder="Postal Code" style="padding: 8px; border: 1px solid #bdc3c7; border-radius: 4px; box-sizing: border-box;">\n                        </div>\n                        <input type="text" id="billingCountry" name="billingCountry" placeholder="Country" style="width: 100%; padding: 8px; border: 1px solid #bdc3c7; border-radius: 4px; box-sizing: border-box;">\n                    </div>\n\n                    <div style="margin-bottom: 20px;">\n                        <label style="display: flex; align-items: flex-start; cursor: pointer;">\n                            <input type="checkbox" id="agreeTerms" name="agreeTerms" required style="margin-right: 8px; margin-top: 3px;">\n                            <span style="color: #34495e; font-size: 13px;">I agree to the <a href="#" onclick="return openInfoModal(\'termsModal\');" style="color: #3498db; text-decoration: none;">Terms &amp; Conditions</a> and <a href="#" onclick="return openInfoModal(\'termsModal\');" style="color: #3498db; text-decoration: none;">Cancellation Policy</a></span>\n                        </label>\n                    </div>\n\n                    <div style="display:flex;align-items:center;justify-content:center;gap:8px;margin-bottom:14px;flex-wrap:wrap;">\n                        <span data-i18n="secure-payments-via" style="font-size:0.78rem;opacity:0.7;flex-shrink:0;">Secure payments via</span>\n                        <a href="https://www.visaeurope.com/" target="_blank" rel="noopener noreferrer" aria-label="Visit Visa">\n                            <img src="logos/Acceptance_mark/Visa_actual/Visa%202015%2050.gif" alt="Visa" width="36" height="22" style="border-radius:3px;background:#fff;padding:2px 4px;width:36px;height:22px;object-fit:contain;">\n                        </a>\n                        <a href="http://www.mastercard.com/" target="_blank" rel="noopener noreferrer" aria-label="Visit Mastercard">\n                            <img src="logos/Acceptance_mark/Mastercard_actual/Artwork/Mastercard%20Brand%20Mark%20Vertical%2053px%20PNG/mc_vrt_opt_pos_53_1x.png" alt="Mastercard" width="36" height="22" style="border-radius:3px;background:#fff;padding:2px 4px;width:36px;height:22px;object-fit:contain;">\n                        </a>\n                        <a href="https://brand.mastercard.com/brandcenter/more-about-our-brands.html" target="_blank" rel="noopener noreferrer" aria-label="Visit Maestro">\n                            <img src="logos/Acceptance_mark/Maestro_actual/Artwork/PNG%20for%20Web/Horizontal/Positive/75px%20x%2021px/ms_hrz_opt_pos_75_1x.png" alt="Maestro" width="36" height="22" style="border-radius:3px;background:#fff;padding:2px 4px;width:36px;height:22px;object-fit:contain;">\n                        </a>\n                        <img src="logos/Security_programs/Visa%20Secure/Visa%20Blue/visa-secure_blu_72dpi.jpg" alt="Visa Secure" width="36" height="22" style="border-radius:3px;background:#fff;padding:2px 4px;width:36px;height:22px;object-fit:contain;">\n                        <img src="logos/Security_programs/Mastercard%20Identity%20Check/Artwork/mc_idcheck_hrz_rgb_pos.png" alt="Mastercard Identity Check" width="36" height="22" style="border-radius:3px;background:#fff;padding:2px 4px;width:36px;height:22px;object-fit:contain;">\n                        <a href="http://monri.com/" target="_blank" rel="noopener noreferrer" aria-label="Visit Monri">\n                            <img src="logos/Monri_badge/monri_badge.png" alt="pay@web · Secured by Monri · UniCredit Bank" width="90" height="42" style="border-radius:3px;background:#fff;padding:2px 4px;width:90px;height:42px;object-fit:contain;">\n                        </a>\n                        <img src="logos/UniCredit_Bank_logo_1.png" alt="UniCredit Bank" width="70" height="42" style="border-radius:3px;background:#fff;padding:2px 4px;width:70px;height:42px;object-fit:contain;">\n                        <a href="https://www.raiffeisenbank.ba/" target="_blank" rel="noopener noreferrer" aria-label="Visit Raiffeisen Bank">\n                            <img src="logos/download.png" alt="Raiffeisen Bank" width="36" height="22" style="border-radius:3px;background:#fff;padding:2px 4px;width:36px;height:22px;object-fit:contain;">\n                        </a>\n                    </div>\n\n                    <div style="display: flex; gap: 10px;">\n                        <button type="submit" id="confirmPaymentBtn" class="btn btn-primary" style="flex: 1; padding: 12px;">Complete Payment</button>\n                        <button type="button" id="cancelConfirmBtn" class="btn btn-secondary" style="flex: 1; padding: 12px;">Cancel</button>\n                    </div>\n                </form>\n            </div>\n        </div>\n    ',bookingSuccessModalTemplate:'\n        <div id="bookingSuccessModal" role="dialog" aria-modal="true" aria-labelledby="successModalTitle" style="display:none; position:fixed; inset:0; z-index:9999; background:rgba(0,0,0,0.6); backdrop-filter:blur(4px); align-items:center; justify-content:center; padding:16px;">\n            <div style="background:#fff; border-radius:20px; max-width:480px; width:100%; padding:48px 36px 36px; text-align:center; position:relative; box-shadow:0 25px 60px rgba(0,0,0,0.25); animation:successModalIn 0.35s cubic-bezier(0.34,1.56,0.64,1);">\n\n                <button id="successModalClose" aria-label="Close" style="position:absolute; top:14px; right:18px; background:none; border:none; font-size:24px; cursor:pointer; color:#999; line-height:1;">&#x2715;</button>\n\n                <div style="width:80px; height:80px; border-radius:50%; background:linear-gradient(135deg,#22c55e,#16a34a); display:flex; align-items:center; justify-content:center; margin:0 auto 24px; box-shadow:0 8px 24px rgba(34,197,94,0.35);">\n                    <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>\n                </div>\n\n                <h2 id="successModalTitle" style="font-size:1.6rem; color:#2c3e50; margin:0 0 8px; font-weight:700;">Booking Request Sent!</h2>\n                <p style="color:#64748b; margin:0 0 28px; font-size:0.95rem;">Thank you — we have received your request and will reply to your email shortly to confirm.</p>\n\n                <div style="background:#f8fafc; border:1px solid #e2e8f0; border-radius:12px; padding:20px; text-align:left; margin-bottom:24px;">\n                    <div style="display:flex; align-items:center; gap:8px; margin-bottom:14px;">\n                        <span style="font-size:18px;">&#127976;</span>\n                        <strong style="color:#2c3e50; font-size:0.95rem;">Booking Summary</strong>\n                    </div>\n                    <table style="width:100%; border-collapse:collapse; font-size:0.875rem; color:#475569;">\n                        <tr><td style="padding:4px 0; color:#94a3b8; width:42%;">Guest</td><td id="sm_name" style="font-weight:600; color:#2c3e50;"></td></tr>\n                        <tr><td style="padding:4px 0; color:#94a3b8;">Email</td><td id="sm_email" style="font-weight:600; color:#2c3e50; word-break:break-all;"></td></tr>\n                        <tr><td style="padding:4px 0; color:#94a3b8;">Room</td><td id="sm_room" style="font-weight:600; color:#2c3e50;"></td></tr>\n                        <tr><td style="padding:4px 0; color:#94a3b8;">Check-in</td><td id="sm_checkin" style="font-weight:600; color:#2c3e50;"></td></tr>\n                        <tr><td style="padding:4px 0; color:#94a3b8;">Check-out</td><td id="sm_checkout" style="font-weight:600; color:#2c3e50;"></td></tr>\n                        <tr><td style="padding:4px 0; color:#94a3b8;">Guests</td><td id="sm_guests" style="font-weight:600; color:#2c3e50;"></td></tr>\n                    </table>\n                </div>\n\n                <div style="background:#eff6ff; border:1px solid #bfdbfe; border-radius:10px; padding:12px 16px; display:flex; align-items:center; gap:10px; margin-bottom:28px; text-align:left;">\n                    <span style="font-size:20px; flex-shrink:0;">&#128231;</span>\n                    <span style="font-size:0.8rem; color:#1d4ed8; line-height:1.4;">Confirmation sent to <strong>about@hotelsinanhan.com</strong>. We will reply directly to your email to confirm the reservation.</span>\n                </div>\n\n                <button id="successModalBtn" style="width:100%; padding:14px; background:linear-gradient(135deg,#4f46e5,#6366f1); color:#fff; border:none; border-radius:12px; font-size:1rem; font-weight:600; cursor:pointer; transition:opacity 0.2s;">Got it, thank you!</button>\n            </div>\n        </div>\n    ',houseRulesModalTemplate:'\n        <div id="houseRulesModal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;align-items:center;justify-content:center;padding:1rem;">\n            <div style="background:#fff;border-radius:12px;max-width:680px;width:100%;max-height:88vh;overflow-y:auto;padding:2rem;position:relative;">\n                <button onclick="return closeInfoModal(\'houseRulesModal\');" style="position:absolute;top:12px;right:16px;background:none;border:none;font-size:26px;cursor:pointer;color:#666;">&times;</button>\n                <h2 style="color:#2c3e50;margin-bottom:1.5rem;font-size:1.5rem;" data-i18n="hr-title">House Rules</h2>\n                <p style="color:#888;font-style:italic;margin-bottom:1.5rem;" data-i18n="hr-special-requests">Hotel Sinan Han takes special requests — add in the next step!</p>\n\n                <div style="display:grid;gap:1.2rem;">\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-checkin-title">Check-in</h4>\n                        <p data-i18n="hr-checkin-time">From 14:00 to 00:00</p>\n                        <p style="color:#666;font-size:.9rem;" data-i18n="hr-checkin-note">You\'ll need to let the property know in advance what time you\'ll arrive.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-checkout-title">Check-out</h4>\n                        <p data-i18n="hr-checkout-time">From 07:00 to 11:00</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-cancellation-title">Cancellation / Prepayment</h4>\n                        <p data-i18n="hr-cancellation-text">Cancellation and prepayment policies vary according to accommodation type. Please enter the dates of your stay and check the conditions of your required option.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-children-title">Children and Beds</h4>\n                        <p style="margin-bottom:.5rem;"><strong data-i18n="hr-child-policies">Child policies</strong></p>\n                        <p data-i18n="hr-children-welcome">Children of any age are welcome.</p>\n                        <p style="margin:.4rem 0;" data-i18n="hr-children-adult-charge">Children 7 years and above will be charged as adults at this property.</p>\n                        <p data-i18n="hr-children-under7">If you are travelling with children under 7 years, to ensure you pay the correct price please select a rate that has child occupancy specified.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-cot-title">Cot and Extra Bed Policies</h4>\n                        <p style="margin-bottom:.4rem;"><strong data-i18n="hr-cot-label">0 – 3 years:</strong> <span data-i18n="hr-cot-free">Cot upon request — Free</span></p>\n                        <p data-i18n="hr-cot-note">The number of cots allowed is dependent on the option you choose. Please check your selected option for more information.</p>\n                        <p style="margin-top:.4rem;" data-i18n="hr-no-extra-beds">There are no extra beds available at this property.</p>\n                        <p data-i18n="hr-cots-availability">All cots are subject to availability.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-age-title">Age Restriction</h4>\n                        <p data-i18n="hr-age-text">There is no age requirement for check-in.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="hr-pets-title">Pets</h4>\n                        <p data-i18n="hr-pets-text">Pets are not allowed.</p>\n                    </div>\n                </div>\n            </div>\n        </div>\n    ',legalInfoModalTemplate:'\n        <div id="legalInfoModal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;align-items:center;justify-content:center;padding:1rem;">\n            <div style="background:#fff;border-radius:12px;max-width:680px;width:100%;max-height:88vh;overflow-y:auto;padding:2rem;position:relative;">\n                <button onclick="return closeInfoModal(\'legalInfoModal\');" style="position:absolute;top:12px;right:16px;background:none;border:none;font-size:26px;cursor:pointer;color:#666;">&times;</button>\n                <h2 style="color:#2c3e50;margin-bottom:1.5rem;font-size:1.5rem;" data-i18n="li-title">Important Legal &amp; Info</h2>\n\n                <div style="display:grid;gap:1.2rem;">\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="li-arrival-title">Arrival Time</h4>\n                        <p data-i18n="li-arrival-text">Please inform Hotel Sinan Han in advance of your expected arrival time. You can use the Special Requests box when booking, or contact the property directly with the contact details provided in your confirmation.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.4rem;" data-i18n="li-health-title">Health &amp; Safety</h4>\n                        <p data-i18n="li-health-text">In response to Coronavirus (COVID-19), additional safety and sanitation measures are in effect at this property.</p>\n                    </div>\n                </div>\n            </div>\n        </div>\n    ',registrationModalTemplate:'\n        <div id="registrationModal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;align-items:center;justify-content:center;padding:1rem;">\n            <div style="background:#fff;border-radius:12px;max-width:680px;width:100%;max-height:88vh;overflow-y:auto;padding:2rem;position:relative;">\n                <button onclick="return closeInfoModal(\'registrationModal\');" style="position:absolute;top:12px;right:16px;background:none;border:none;font-size:26px;cursor:pointer;color:#666;">&times;</button>\n                <h2 style="color:#2c3e50;margin-bottom:1.5rem;font-size:1.4rem;" data-i18n="reg-title">Business Classification Notice</h2>\n                <div style="font-size:0.9rem;color:#444;line-height:1.8;display:grid;gap:0.6rem;">\n                    <p style="text-align:center;font-weight:700;" data-i18n="reg-country">BOSNA I HERCEGOVINA</p>\n                    <p style="text-align:center;font-weight:700;" data-i18n="reg-entity">FEDERACIJA BOSNE I HERCEGOVINE</p>\n                    <p style="text-align:center;font-weight:700;" data-i18n="reg-institute">FEDERALNI ZAVOD ZA STATISTIKU SARAJEVO</p>\n                    <p style="text-align:center;font-weight:700;" data-i18n="reg-dept">SLUŽBA ZA STATISTIKU ZA PODRUČJE HERCEGOVAČKO-NERETVANSKOG KANTONA MOSTAR</p>\n                    <p style="margin-top:0.8rem;"><strong data-i18n="reg-number-label">Broj:</strong> 07-28-5-12683/25</p>\n                    <p><strong data-i18n="reg-date-label">Datum:</strong> 26.09.2025.</p>\n                    <p style="margin-top:0.8rem;" data-i18n="reg-law-basis">Na osnovu člana 7. stav (1) i člana 11. Zakona o klasifikaciji djelatnosti u Federaciji Bosne i Hercegovine ("Službene novine Federacije BiH", br. 64/07 i 80/11), izdaje se:</p>\n                    <p style="text-align:center;font-weight:700;margin-top:0.8rem;" data-i18n="reg-notice-title">OBAVJEŠTENJE O RAZVRSTAVANJU POSLOVNOG SUBJEKTA PREMA KLASIFIKACIJI DJELATNOSTI</p>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;margin-top:0.8rem;display:grid;gap:0.4rem;">\n                        <p><strong data-i18n="reg-name-label">Naziv poslovnog subjekta:</strong> <span data-i18n="reg-name-value">Sobe u domaćinstvu "SINAN-HAN" vl. Arif Jašari</span></p>\n                        <p><strong data-i18n="reg-address-label">Sjedište i adresa:</strong> Gojka Vukovića broj 20 A, MOSTAR</p>\n                        <p><strong data-i18n="reg-id-label">Identifikacioni broj (ID):</strong> 4329213370002</p>\n                        <p><strong data-i18n="reg-code-label">Šifra djelatnosti (KD BIH 2010):</strong> 55.20</p>\n                        <p><strong data-i18n="reg-activity-label">Naziv djelatnosti:</strong> <span data-i18n="reg-activity-value">Odmarališta i slični objekti za kraći odmor</span></p>\n                    </div>\n                    <div style="margin-top:1rem;border-top:1px solid #e0d6c8;padding-top:1rem;display:grid;gap:0.5rem;">\n                        <p style="font-weight:600;" data-i18n="reg-explanation-title">Obrazloženje:</p>\n                        <p data-i18n="reg-explanation-p1">U postupku provedenom po zahtjevu stranke, odnosno službenoj dužnosti, utvrđeno je da su ispunjene pretpostavke iz člana 9. i 11. Zakona o klasifikaciji djelatnosti u Federaciji Bosne i Hercegovine, za izdavanje ovog obavještenja.</p>\n                        <p data-i18n="reg-explanation-p2">Ukoliko poslovni subjekt smatra da je nepravilno razvrstan, ima pravo u roku od 15 dana od dana prijema ovog obavještenja podnijeti ovom Zavodu zahtjev za ponovno razvrstavanje sa potrebnom dokumentacijom.</p>\n                    </div>\n                    <div style="margin-top:1.2rem;display:flex;justify-content:flex-end;">\n                        <div style="text-align:center;font-size:0.85rem;color:#444;">\n                            <p style="font-weight:600;letter-spacing:0.03em;" data-i18n="reg-authority-title">OVLAŠTENJU DIREKTORA NAČELNIK</p>\n                            <p style="margin-top:0.4rem;font-weight:700;letter-spacing:0.05em;">AZIZ DEDOVIĆ</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    ',termsModalTemplate:'\n        <div id="termsModal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;align-items:center;justify-content:center;padding:1rem;">\n            <div style="background:#fff;border-radius:12px;max-width:720px;width:100%;max-height:88vh;overflow-y:auto;padding:2rem;position:relative;">\n                <button onclick="return closeInfoModal(\'termsModal\');" style="position:absolute;top:12px;right:16px;background:none;border:none;font-size:26px;cursor:pointer;color:#666;">&times;</button>\n                <h2 style="color:#2c3e50;margin-bottom:0.4rem;font-size:1.45rem;" data-i18n="tpc-modal-title">Terms of Use, Privacy &amp; Purchase Policy</h2>\n                <p style="color:#888;font-size:0.82rem;margin-bottom:1.8rem;" data-i18n="tpc-last-updated">Last updated: June 2026</p>\n\n                <div style="display:grid;gap:1.4rem;">\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-company-title">Service Provider</h4>\n                        <p style="margin-bottom:.3rem;"><strong data-i18n="tpc-company-name">Sobe u domaćinstvu &#8222;SINAN-HAN&#8220;</strong></p>\n                        <p style="color:#555;font-size:.9rem;" data-i18n="tpc-company-address">vl. Arif Jašari &nbsp;|&nbsp; Ul. Braće Fejzića bb, Mostar, BiH</p>\n                        <p style="color:#555;font-size:.9rem;" data-i18n="tpc-company-registry">MBS: 58-01-0026-21 &nbsp;|&nbsp; JIB: 4323213370002</p>\n                        <p style="color:#555;font-size:.9rem;"><span data-i18n="tpc-company-phone-label">Tel:</span> <a href="tel:+38736834784" style="color:#c19a6b;">+387 36 834 784</a> &nbsp;|&nbsp; <a href="tel:+38763800009" style="color:#c19a6b;">+387 63 800 009</a></p>\n                        <p style="color:#555;font-size:.9rem;"><span data-i18n="tpc-company-email-label">Email:</span> <a href="mailto:about@hotelsinanhan.com" style="color:#c19a6b;">about@hotelsinanhan.com</a></p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-general-title">General Terms &amp; Conditions</h4>\n                        <p style="margin-bottom:.6rem;" data-i18n="tpc-general-p1">These Terms govern the booking, payment, and use of accommodation services provided by Guesthouse Sinan Han. By completing a booking you confirm that you have read and agree to all terms and conditions set out herein.</p>\n                        <p data-i18n="tpc-general-p2">The service provider commits to deliver the accommodation as described on the website and to act in the best interest of the guest in accordance with hospitality industry standards. The provider is responsible for damages caused to the guest by non-fulfilment or improper fulfilment of the contracted service.</p>\n                        <p style="margin-top:.6rem;" data-i18n="tpc-general-p3">In the event of extraordinary and unforeseeable circumstances beyond the control of the provider (force majeure — war, natural disaster, pandemic, strikes, etc.), the provider may modify or cancel the reservation. In such cases the guest is entitled to a full refund of any amount paid.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-obligations-title">Guest Obligations</h4>\n                        <p style="margin-bottom:.6rem;" data-i18n="tpc-obligations-p1">The guest agrees to pay the agreed price in accordance with these terms. The guest must provide all data required for the booking to be correctly processed and ensure that they and their travel documents comply with all applicable entry, health, and customs regulations.</p>\n                        <p data-i18n="tpc-obligations-p2">The guest is responsible for any damage caused by failure to fulfil their obligations. Any complaint regarding the service must be submitted in writing within 8 days of check-out.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-cancellation-title">Booking &amp; Cancellation Policy</h4>\n                        <p style="margin-bottom:.6rem;" data-i18n="tpc-cancellation-p1">Bookings are made via the online reservation form. A booking is confirmed upon receipt of payment. In the event of guest cancellation, the following charges apply (unless stated otherwise in the specific offer):</p>\n                        <ul style="margin:.4rem 0 .6rem 1.2rem;color:#444;line-height:1.9;font-size:.92rem;">\n                            <li data-i18n="tpc-cancel-tier1">More than 30 days before arrival: 30% of the total amount</li>\n                            <li data-i18n="tpc-cancel-tier2">15–30 days before arrival: 60% of the total amount</li>\n                            <li data-i18n="tpc-cancel-tier3">Less than 15 days before arrival or no-show: 100% of the total amount</li>\n                        </ul>\n                        <p data-i18n="tpc-cancellation-p2">All cancellations must be submitted in writing by email. If the provider significantly changes the accommodation or price before arrival, the guest will be notified in writing and may accept the change or cancel with a full refund within 2 working days.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-payment-title">Payment Methods</h4>\n                        <p style="margin-bottom:.8rem;" data-i18n="tpc-payment-p1">Payments are processed securely online via the following credit and debit cards:</p>\n                        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;background:#f8f8f8;border:1px solid #e0e0e0;border-radius:8px;padding:10px 16px;">\n                            <img src="logos/Acceptance_mark/Visa_actual/Visa%202015%2050.gif" alt="Visa" style="height:28px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/Acceptance_mark/Mastercard_actual/Artwork/Mastercard%20Brand%20Mark%20Vertical%2053px%20PNG/mc_vrt_opt_pos_53_1x.png" alt="Mastercard" style="height:28px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/Acceptance_mark/Maestro_actual/Artwork/PNG%20for%20Web/Horizontal/Positive/75px%20x%2021px/ms_hrz_opt_pos_75_1x.png" alt="Maestro" style="height:28px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/Security_programs/Visa%20Secure/Visa%20Blue/visa-secure_blu_72dpi.jpg" alt="Visa Secure" style="height:28px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/Security_programs/Mastercard%20Identity%20Check/Artwork/mc_idcheck_hrz_rgb_pos.png" alt="Mastercard Identity Check" style="height:28px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/Monri_badge/monri_badge.png" alt="Secured by Monri" style="height:42px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/UniCredit_Bank_logo_1.png" alt="UniCredit Bank" style="height:36px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                            <img src="logos/download.png" alt="Raiffeisen Bank" style="height:28px;width:auto;background:#fff;border-radius:3px;padding:2px 5px;object-fit:contain;">\n                        </div>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-security-title">Secure Payment</h4>\n                        <p style="margin-bottom:.5rem;" data-i18n="tpc-security-p1">Your personal and payment data is protected using SSL 128-bit encryption. Pages for web payment are secured using the Secure Socket Layer (SSL) protocol, preventing any unauthorized access during data transfer.</p>\n                        <p style="margin-bottom:.5rem;" data-i18n="tpc-security-p2">Monri Payments is a PCI DSS Level 1 certified payment service provider. The Monri WebPay Payment Gateway and financial institutions exchange data via a virtual private network (VPN) protected from unauthorized access.</p>\n                        <p data-i18n="tpc-security-p3">Credit card numbers are not stored by the merchant and are not accessible to unauthorized personnel.</p>\n                        <p style="margin-top:.5rem;font-size:.85rem;color:#777;" data-i18n="tpc-security-p4">All payments are processed in BAM (Bosnian Convertible Mark). Any currency conversion to your local currency is performed by your card issuer at their applicable exchange rate.</p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-complaints-title">Complaints</h4>\n                        <p style="margin-bottom:.5rem;" data-i18n="tpc-complaints-p1">Guests have the right to file a written complaint for any contracted service not delivered. Complaints must be submitted within 8 days of check-out. Complaints submitted after this deadline will not be considered.</p>\n                        <p style="margin-bottom:.5rem;" data-i18n="tpc-complaints-p2">It is in the guest\'s interest to first raise any issue directly with the service provider on-site and obtain written acknowledgement. The provider will respond in writing within 15 days of receiving the complaint.</p>\n                        <p style="font-size:.85rem;color:#777;" data-i18n="tpc-complaints-p3">For online dispute resolution, consumers may submit a complaint via the EU ODR platform: <a href="http://ec.europa.eu/consumers/odr/" target="_blank" rel="noopener noreferrer" style="color:#c19a6b;">ec.europa.eu/consumers/odr</a></p>\n                    </div>\n                    <div style="border-left:3px solid #c19a6b;padding-left:1rem;">\n                        <h4 style="color:#c19a6b;margin-bottom:.6rem;" data-i18n="tpc-privacy-title">Personal Data Protection</h4>\n                        <p style="margin-bottom:.5rem;" data-i18n="tpc-privacy-p1">We collect only the minimum personal data necessary to fulfil our booking obligations (name, email, phone number). We inform guests about how collected data is used and provide the option to opt out of marketing communications.</p>\n                        <p data-i18n="tpc-privacy-p2">All personal data is strictly guarded and accessible only to employees who require it to perform their duties. All employees and business partners are bound by confidentiality obligations. The provider reserves the right to amend these terms; any changes will be published on this website.</p>\n                    </div>\n                </div>\n            </div>\n        </div>\n    '});